def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0
        decay = 1.0
        adjustment = 1.0
        for j in range(1, 20):
            if j % 4 == 0:
                factor = 1.3
            elif j % 5 == 0:
                factor = 1.15
            elif j % 2 == 0:
                factor = 0.9
            else:
                factor = 0.75
            term = factor * np.exp(-0.1 * j) * (ratio ** (j + 1)) / (j ** 1.5)
            score += term
            if term < 1e-6:
                break
            if j % 3 == 0:
                adjustment *= 1.05
            else:
                adjustment *= 0.98
        score *= adjustment
        free_ratio = (capacity - item) / capacity
        if free_ratio < 0.05:
            score *= 3.0
        elif free_ratio < 0.15:
            score *= 1.6
        elif free_ratio < 0.25:
            score *= 1.2
        else:
            score *= 0.65
        mods = (int(capacity) % 2 == 0, int(capacity) % 3 == 0, int(capacity) % 5 == 0, int(capacity) % 7 == 0)
        mod_factor = 0
        if mods[0] and mods[1] and mods[2]:
            mod_factor -= 0.18 * capacity / 12
        elif mods[1] and mods[3]:
            mod_factor -= 0.2 * capacity / 18
        elif mods[2] and mods[3]:
            mod_factor -= 0.15 * capacity / 22
        elif mods[0] and mods[2]:
            mod_factor -= 0.12 * capacity / 20
        elif mods[1]:
            mod_factor -= 0.05 * capacity / 15
        elif mods[2]:
            mod_factor -= 0.07 * capacity / 25
        else:
            mod_factor -= 0.03 * capacity / 35
        score += mod_factor
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * k
            if diff < threshold / 2:
                penalty += 0.3 * k
            elif diff < threshold:
                penalty += 0.15 * k
            elif diff < 1.5 * threshold:
                penalty -= 0.08 * k
            else:
                penalty -= 0.1 * k
            if k % 2 == 0:
                penalty += 0.02 * k
            else:
                penalty -= 0.01 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2:
            for m in range(1, 5):
                target = capacity / m
                tolerance = 0.025 * target
                if abs(target - item) < tolerance:
                    score *= (1 + 0.07 * m)
                    break
        primes = [2,3,5,7,11,13]
        prime_bonus = 0
        for p in primes:
            if int(capacity) % p == 0 and abs((capacity / p) - item) < 0.03 * (capacity / p):
                prime_bonus += 0.04 * p
            elif abs(capacity - item * p) < 0.04 * capacity:
                prime_bonus += 0.03 * p
            else:
                prime_bonus -= 0.015 * p
        score += prime_bonus
        if score < 0:
            score = 0
        if score > 5:
            score = 5 + np.log1p(score - 5)
        priorities[i] = score
    return priorities
